const body = $input.first().json.body || $input.first().json;
const projectId = body.projectId || 'unknown';
const tasks = body.tasks || [];

// 简单排期逻辑
const DAILY_HOURS = 8;
let currentDate = new Date();
const suggestions = tasks.map(task => {
  const daysNeeded = Math.ceil((task.estimatedHours || 4) / DAILY_HOURS);
  const startDate = new Date(currentDate);
  currentDate = new Date(currentDate.getTime() + daysNeeded * 24 * 60 * 60 * 1000);
  return {
    taskId: task.id,
    title: task.title,
    priority: task.priority || 'MEDIUM',
    estimatedHours: task.estimatedHours || 4,
    suggestedStart: startDate.toISOString().split('T')[0],
    suggestedEnd: currentDate.toISOString().split('T')[0],
    daysNeeded,
  };
});

return [{
  json: {
    projectId,
    suggestions,
    totalDays: Math.ceil(tasks.reduce((sum, t) => sum + (t.estimatedHours || 4), 0) / DAILY_HOURS),
    message: `已为 ${tasks.length} 个任务生成排期建议`,
  }
}];
